#!/usr/bin/env python3
"""Author the conformance fixtures and (re)generate expected/*.json.

Run this only when intentionally changing the conformance corpus:
    python3 conformance/regen.py

It writes fixtures under conformance/fixtures/{valid,invalid}/<name>/, builds each
fixture's manifest (so the ONLY failures are the intended ones), and records the
reference validator's --json output as conformance/expected/<name>.json. Review the
diff after running: each expected file must reflect the fixture's INTENDED outcome.

conformance/run.sh is the runner (diffs live output vs expected); this is the author.
"""
import json
import os
import shutil
import sys

HERE = os.path.dirname(os.path.abspath(__file__))
ROOT = os.path.dirname(HERE)
sys.path.insert(0, os.path.join(ROOT, "tools"))
import build_manifest  # noqa: E402
import validate  # noqa: E402

FIX = os.path.join(HERE, "fixtures")
EXP = os.path.join(HERE, "expected")


def doc(type="concept", title="A Doc",
        description="Use when you need a valid reference document for tests.",
        status="active", timestamp="2026-06-21", extra=None, body="Body text.\n"):
    fm = {"type": type, "title": title, "description": description,
          "status": status, "timestamp": timestamp}
    if extra:
        fm.update(extra)
    lines = ["---"]
    for k, v in fm.items():
        if isinstance(v, list):
            lines.append(f"{k}: [{', '.join(v)}]")
        else:
            lines.append(f"{k}: {v}")
    lines.append("---")
    return "\n".join(lines) + "\n\n" + body


# name -> {files: {relpath: content}, manifest: "build"|"stale"|"none"}
FIXTURES = {
    # ---- valid ----
    "valid_minimal": {
        "files": {"index.md": doc(type="index", title="Minimal",
                                  description="Use when orienting to the minimal valid fixture bundle.")},
        "manifest": "build",
    },
    "valid_cb_ok": {
        "files": {
            "index.md": doc(type="index", title="CB OK",
                            description="Use when orienting to the valid CB-tier fixture bundle."),
            "base.md": doc(type="concept", title="Base",
                           description="Use when you need the base belief the derived one depends on.",
                           extra={"tier": "cb", "id": "fix:base"}),
            "derived.md": doc(type="concept", title="Derived",
                              description="Use when you need the derived belief composed from the base.",
                              extra={"tier": "cb", "id": "fix:derived", "deps": ["fix:base"]}),
        },
        "manifest": "build",
    },
    # ---- invalid: one targeted error each ----
    "invalid_bad_type": {
        "files": {"index.md": doc(type="gizmo", title="Bad Type",
                                  description="Use when testing a type outside the closed taxonomy.")},
        "manifest": "build",
    },
    "invalid_weak_description": {
        "files": {"index.md": doc(type="index", title="Weak Desc", description="short")},
        "manifest": "build",
    },
    "invalid_placeholder": {
        "files": {"index.md": doc(type="index", title="<Name>",
                                  description="Use when testing an unfilled template placeholder.")},
        "manifest": "build",
    },
    "invalid_status": {
        "files": {"index.md": doc(type="index", title="Bad Status", status="foo",
                                  description="Use when testing an invalid status value.")},
        "manifest": "build",
    },
    "invalid_timestamp": {
        "files": {"index.md": doc(type="index", title="Bad Date", timestamp="2026/01/01",
                                  description="Use when testing a non-ISO timestamp value.")},
        "manifest": "build",
    },
    "invalid_broken_link": {
        "files": {"index.md": doc(type="index", title="Broken Link",
                                  description="Use when testing a link to a nonexistent document.",
                                  body="See [missing](nope.md).\n")},
        "manifest": "build",
    },
    "invalid_cb_no_id": {
        "files": {"index.md": doc(type="concept", title="CB No Id",
                                  description="Use when testing a CB-tier doc that omits its id.",
                                  extra={"tier": "cb"})},
        "manifest": "build",
    },
    "invalid_dup_id": {
        "files": {
            "index.md": doc(type="index", title="Dup A",
                            description="Use when testing the first of two docs sharing an id.",
                            extra={"id": "fix:dup"}),
            "other.md": doc(type="concept", title="Dup B",
                            description="Use when testing the second of two docs sharing an id.",
                            extra={"id": "fix:dup"}),
        },
        "manifest": "build",
    },
    "invalid_stale_manifest": {
        "files": {"index.md": doc(type="index", title="Stale",
                                  description="Use when testing a manifest that no longer matches docs.")},
        "manifest": "stale",
    },
    "invalid_missing_manifest": {
        "files": {"index.md": doc(type="index", title="No Manifest",
                                  description="Use when testing a bundle with no manifest at all.")},
        "manifest": "none",
    },
}


def write_fixture(name, spec):
    kind = "valid" if name.startswith("valid_") else "invalid"
    root = os.path.join(FIX, kind, name)
    if os.path.isdir(root):
        shutil.rmtree(root)
    os.makedirs(root)
    for rel, content in spec["files"].items():
        with open(os.path.join(root, rel), "w", encoding="utf-8") as f:
            f.write(content)
    mode = spec["manifest"]
    if mode in ("build", "stale"):
        man = build_manifest.build(root)
        if mode == "stale":
            man["count"] = 999  # deliberately wrong -> manifest_stale
        with open(os.path.join(root, "manifest.json"), "w", encoding="utf-8") as f:
            f.write(json.dumps(man, indent=2, ensure_ascii=False) + "\n")
    return root


def main():
    os.makedirs(EXP, exist_ok=True)
    for name, spec in FIXTURES.items():
        root = write_fixture(name, spec)
        errors, warnings = validate.validate(root)
        out = {
            "ok": not errors,
            "errors": validate._sorted_pairs(errors),
            "warnings": validate._sorted_pairs(warnings),
        }
        with open(os.path.join(EXP, f"{name}.json"), "w", encoding="utf-8") as f:
            f.write(json.dumps(out, indent=2, ensure_ascii=False) + "\n")
        print(f"{name}: ok={out['ok']} "
              f"errors={[e['code'] for e in out['errors']]} "
              f"warnings={[w['code'] for w in out['warnings']]}")


if __name__ == "__main__":
    main()

